import { useState } from 'react'
import {
  useReactTable,
  getCoreRowModel,
  flexRender,
  ColumnDef,
} from '@tanstack/react-table'
import { useForm } from '@tanstack/react-form'
import './App.css'

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
}

const initialUsers: User[] = [
  { id: '1', name: 'Alice Johnson', email: 'alice@example.com', role: 'Admin' },
  { id: '2', name: 'Bob Smith', email: 'bob@example.com', role: 'User' },
  { id: '3', name: 'Charlie Brown', email: 'charlie@example.com', role: 'Editor' },
];

const columns: ColumnDef<User>[] = [
  {
    accessorKey: 'id',
    header: 'ID',
    cell: ({ getValue }) => <span className="id-cell">{getValue() as string}</span>,
  },
  {
    accessorKey: 'name',
    header: 'Name',
    cell: ({ getValue, row, table }) => {
      const meta = table.options.meta as any;
      const isEditing = meta?.editingRowId === row.original.id;
      if (isEditing) {
        return (
          <meta.form.Field
            name="name"
            validators={{
              onChange: ({ value }: { value: string }) => !value ? 'Name is required' : undefined,
            }}
          >
            {(field: any) => (
              <div className="input-container">
                <input
                  value={field.state.value}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className={`edit-input ${field.state.meta.errors.length ? 'input-error' : ''}`}
                  placeholder="Name"
                />
                {field.state.meta.errors.length ? (
                  <span className="error-message">{field.state.meta.errors[0]}</span>
                ) : null}
              </div>
            )}
          </meta.form.Field>
        );
      }
      return getValue() as string;
    },
  },
  {
    accessorKey: 'email',
    header: 'Email',
    cell: ({ getValue, row, table }) => {
      const meta = table.options.meta as any;
      const isEditing = meta?.editingRowId === row.original.id;
      if (isEditing) {
        return (
          <meta.form.Field
            name="email"
            validators={{
              onChange: ({ value }: { value: string }) => {
                if (!value) return 'Email is required';
                const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                if (!emailRegex.test(value)) return 'Invalid email format';
                return undefined;
              },
            }}
          >
            {(field: any) => (
              <div className="input-container">
                <input
                  type="email"
                  value={field.state.value}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className={`edit-input ${field.state.meta.errors.length ? 'input-error' : ''}`}
                  placeholder="Email"
                />
                {field.state.meta.errors.length ? (
                  <span className="error-message">{field.state.meta.errors[0]}</span>
                ) : null}
              </div>
            )}
          </meta.form.Field>
        );
      }
      return getValue() as string;
    },
  },
  {
    accessorKey: 'role',
    header: 'Role',
    cell: ({ getValue, row, table }) => {
      const meta = table.options.meta as any;
      const isEditing = meta?.editingRowId === row.original.id;
      if (isEditing) {
        return (
          <meta.form.Field
            name="role"
            validators={{
              onChange: ({ value }: { value: string }) => !value ? 'Role is required' : undefined,
            }}
          >
            {(field: any) => (
              <div className="input-container">
                <input
                  value={field.state.value}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className={`edit-input ${field.state.meta.errors.length ? 'input-error' : ''}`}
                  placeholder="Role"
                />
                {field.state.meta.errors.length ? (
                  <span className="error-message">{field.state.meta.errors[0]}</span>
                ) : null}
              </div>
            )}
          </meta.form.Field>
        );
      }
      return getValue() as string;
    },
  },
  {
    id: 'actions',
    header: 'Actions',
    cell: ({ row, table }) => {
      const meta = table.options.meta as any;
      const isEditing = meta?.editingRowId === row.original.id;

      if (isEditing) {
        return (
          <div className="actions-cell">
            <button
              type="button"
              className="btn btn-save"
              onClick={(e) => {
                e.preventDefault();
                meta.form.handleSubmit();
              }}
            >
              Save
            </button>
            <button
              type="button"
              className="btn btn-cancel"
              onClick={() => meta.onCancel()}
            >
              Cancel
            </button>
          </div>
        );
      }

      return (
        <button
          type="button"
          className="btn btn-edit"
          disabled={meta?.editingRowId !== null}
          onClick={() => meta.onEdit(row.original)}
        >
          Edit
        </button>
      );
    },
  },
];

function App() {
  const [data, setData] = useState<User[]>(initialUsers);
  const [editingRowId, setEditingRowId] = useState<string | null>(null);

  const form = useForm({
    defaultValues: {
      id: '',
      name: '',
      email: '',
      role: '',
    },
    onSubmit: async ({ value }) => {
      setData((prev) =>
        prev.map((user) => (user.id === value.id ? value : user))
      );
      setEditingRowId(null);
    },
  });

  const handleEdit = (user: User) => {
    form.reset({
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role,
    });
    setEditingRowId(user.id);
  };

  const handleCancel = () => {
    setEditingRowId(null);
    form.reset();
  };

  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
    meta: {
      editingRowId,
      form,
      onEdit: handleEdit,
      onCancel: handleCancel,
    },
  });

  return (
    <div className="app-container">
      <header className="app-header">
        <h1>User Management Directory</h1>
        <p className="subtitle">
          Manage system users with inline editing powered by TanStack Table and TanStack Form.
        </p>
      </header>

      <main className="table-wrapper">
        <table className="data-table">
          <thead>
            {table.getHeaderGroups().map((headerGroup) => (
              <tr key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <th key={header.id} style={{ width: header.column.getSize() }}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                  </th>
                ))}
              </tr>
            ))}
          </thead>
          <tbody>
            {table.getRowModel().rows.map((row) => (
              <tr
                key={row.id}
                className={editingRowId === row.original.id ? 'row-editing' : ''}
              >
                {row.getVisibleCells().map((cell) => (
                  <td key={cell.id}>
                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </main>
    </div>
  );
}

export default App;

.app-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 40px 20px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;
  color: #333;
}

.app-header {
  text-align: center;
  margin-bottom: 40px;
}

.app-header h1 {
  font-size: 2.5rem;
  font-weight: 700;
  color: #111827;
  margin: 0 0 10px 0;
}

.subtitle {
  font-size: 1.1rem;
  color: #6b7280;
  margin: 0;
}

.table-wrapper {
  background: #ffffff;
  border-radius: 12px;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
  border: 1px solid #e5e7eb;
  overflow-x: auto;
}

.data-table {
  width: 100%;
  border-collapse: collapse;
  text-align: left;
}

.data-table th {
  background-color: #f9fafb;
  padding: 16px 24px;
  font-size: 0.85rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #4b5563;
  border-bottom: 1px solid #e5e7eb;
}

.data-table td {
  padding: 16px 24px;
  border-bottom: 1px solid #e5e7eb;
  vertical-align: middle;
  font-size: 0.95rem;
  color: #1f2937;
}

.data-table tbody tr:hover {
  background-color: #f9fafb;
}

.data-table tbody tr.row-editing {
  background-color: #eff6ff;
}

.id-cell {
  font-weight: 600;
  color: #6b7280;
}

/* Inputs & Validation */
.input-container {
  display: flex;
  flex-direction: column;
  gap: 4px;
  position: relative;
}

.edit-input {
  width: 100%;
  min-width: 160px;
  padding: 8px 12px;
  font-size: 0.95rem;
  border: 1px solid #d1d5db;
  border-radius: 6px;
  outline: none;
  background-color: #ffffff;
  transition: border-color 0.15s ease-in-out, box-shadow 0.15s ease-in-out;
  box-sizing: border-box;
}

.edit-input:focus {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.15);
}

.edit-input.input-error {
  border-color: #ef4444;
  background-color: #fef2f2;
}

.edit-input.input-error:focus {
  box-shadow: 0 0 0 3px rgba(239, 68, 68, 0.15);
}

.error-message {
  font-size: 0.75rem;
  color: #ef4444;
  font-weight: 500;
  margin-top: 2px;
}

/* Buttons */
.actions-cell {
  display: flex;
  gap: 8px;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 16px;
  font-size: 0.875rem;
  font-weight: 500;
  border-radius: 6px;
  border: 1px solid transparent;
  cursor: pointer;
  transition: all 0.15s ease-in-out;
}

.btn-edit {
  background-color: #f3f4f6;
  color: #1f2937;
  border-color: #d1d5db;
}

.btn-edit:hover:not(:disabled) {
  background-color: #e5e7eb;
}

.btn-edit:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn-save {
  background-color: #10b981;
  color: #ffffff;
}

.btn-save:hover {
  background-color: #059669;
}

.btn-cancel {
  background-color: #ef4444;
  color: #ffffff;
}

.btn-cancel:hover {
  background-color: #dc2626;
}

@media (max-width: 768px) {
  .app-container {
    padding: 20px 10px;
  }

  .app-header h1 {
    font-size: 2rem;
  }

  .data-table th, .data-table td {
    padding: 12px 16px;
  }
}
